#!/usr/bin/env python3
import json, sys

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0

    tool = ev.get("tool_name", "")
    inp = ev.get("tool_input") or {}

    if tool != "Bash":
        return 0

    cmd = inp.get("command", "")

    # Block bare `pnpm test` but allow `pnpm test:ci`
    if cmd.strip().startswith("pnpm test") and ":ci" not in cmd:
        print("Use `pnpm test:ci` instead — `pnpm test` opens an interactive watcher that times out.", file=sys.stderr)
        return 2

    return 0

if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""After Edit/Write to Python files, run ruff format then ruff check and surface any remaining issues."""
import json, subprocess, sys, os

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0  # never break Claude Code on bad input

    tool = ev.get("tool_name", "")
    inp  = ev.get("tool_input") or {}
    resp = ev.get("tool_response") or {}

    if tool not in ("Edit", "Write"):
        return 0

    file_path = inp.get("file_path", "")
    if not file_path.endswith(".py"):
        return 0

    # Run ruff format on the file
    try:
        subprocess.run(
            ["ruff", "format", file_path],
            capture_output=True,
            text=True,
            timeout=10,
            cwd=ev.get("cwd", ".")
        )
    except Exception:
        pass  # format failure shouldn't block

    # Run ruff check and surface issues
    try:
        check_result = subprocess.run(
            ["ruff", "check", file_path],
            capture_output=True,
            text=True,
            timeout=10,
            cwd=ev.get("cwd", ".")
        )
        if check_result.returncode != 0 and check_result.stdout.strip():
            lines = check_result.stdout.strip().splitlines()[:15]
            print(f"REQUIRED FOLLOW-UP: ruff check found {len(lines)} issue(s) in {file_path}:", file=sys.stderr)
            for line in lines:
                print(f"  {line}", file=sys.stderr)
            print("Fix each issue, then continue. Do not stop.", file=sys.stderr)
            return 2
    except Exception:
        pass

    return 0

if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
import json, sys, subprocess, re

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0

    tool = ev.get("tool_name", "")
    inp = ev.get("tool_input") or {}

    if tool != "Edit":
        return 0

    fp = inp.get("file_path", "")
    if not (fp.endswith(".ts") or fp.endswith(".js") or fp.endswith(".tsx") or fp.endswith(".jsx")):
        return 0

    old = inp.get("old_string", "")
    new = inp.get("new_string", "")

    # Pattern: export const FOO = 'value'
    pat = r'export\s+const\s+(\w+)\s*=\s*[\'"]([^\'"]+)[\'"]'
    om = re.search(pat, old)
    nm = re.search(pat, new)

    if om and nm and om.group(2) != nm.group(2):
        name, old_val, new_val = om.group(1), om.group(2), nm.group(2)
        print(f"REQUIRED FOLLOW-UP: {name} value changed: '{old_val}' → '{new_val}'", file=sys.stderr)
        print(f"\nAll references to '{old_val}':", file=sys.stderr)
        try:
            r = subprocess.run(["grep", "-rn", "--include=*.ts", "--include=*.js", old_val, "."],
                             capture_output=True, text=True, timeout=5)
            print(r.stdout if r.stdout else "  (none found)", file=sys.stderr)
        except Exception:
            pass
        print(f"\nFix each reference before proceeding.", file=sys.stderr)
        return 2

    return 0

if __name__ == "__main__":
    sys.exit(main())

