#!/usr/bin/env python3
import json
import sys
import subprocess
import os

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0  # never break Claude Code on bad input

    tool = ev.get("tool_name", "")
    inp = ev.get("tool_input") or {}
    resp = ev.get("tool_response") or {}

    # Only check Edit operations
    if tool != "Edit":
        return 0

    file_path = inp.get("file_path", "")

    # Only check Python files
    if not file_path.endswith(".py"):
        return 0

    # Check if file exists after edit
    if not os.path.exists(file_path):
        return 0

    # Run pyflakes to catch undefined names and other simple errors
    try:
        result = subprocess.run(
            ["python3", "-m", "pyflakes", file_path],
            capture_output=True,
            text=True,
            timeout=5
        )

        if result.returncode != 0 and result.stdout.strip():
            # Found issues - REQUIRED FOLLOW-UP
            print(f"REQUIRED FOLLOW-UP: pyflakes found errors in {file_path}:", file=sys.stderr)
            print(result.stdout, file=sys.stderr)
            print("Fix each error before proceeding.", file=sys.stderr)
            return 2

    except (subprocess.TimeoutExpired, FileNotFoundError):
        # pyflakes not available or timeout - don't block
        return 0

    return 0

if __name__ == "__main__":
    sys.exit(main())
